import React, { useState } from "react";
import { auth, provider } from "./firebase";
import { signInWithPopup, signOut } from "firebase/auth";
import axios from "axios";
import IngredientSelector from "./components/IngredientSelector";
import RecipeCard from "./components/RecipeCard";

function App() {
  const [user, setUser] = useState(null);
  const [selectedIngredients, setSelectedIngredients] = useState([]);
  const [recipes, setRecipes] = useState([]);
  const [loading, setLoading] = useState(false);

  const SPOONACULAR_API_KEY = "fe2d7d6a4cab4f95ae4127a1e0536203"; 

  const handleLogin = () => {
    signInWithPopup(auth, provider)
      .then((result) => setUser(result.user))
      .catch((error) => console.error("Login failed", error));
  };

  const handleLogout = () => {
    signOut(auth).then(() => setUser(null));
  };

  const fetchRecipes = async () => {
    if (selectedIngredients.length === 0) return;
    setLoading(true);
    setRecipes([]);
    try {
      const response = await axios.get("https://api.spoonacular.com/recipes/findByIngredients", {
        params: {
          ingredients: selectedIngredients.join(","),
          number: 5,
          apiKey: SPOONACULAR_API_KEY,
        },
      });
      setRecipes(response.data);
    } catch (error) {
      console.error("Error fetching recipes:", error);
    } finally {
      setLoading(false);
    }
  };

  if (!user) {
    return (
      <div className="container" style={{ marginTop: "100px", textAlign: "center" }}>
        <h1>What's In My Fridge</h1>
        <p>Find recipes based on what you have!</p>
        <button onClick={handleLogin} className="button">Sign in with Google</button>
      </div>
    );
  }

  return (
    <div>
      <header>
        <h1>What's In My Fridge</h1>
        <div>
          <span style={{ marginRight: "10px" }}>Welcome, {user.displayName}</span>
          <button onClick={handleLogout} className="button">Logout</button>
        </div>
      </header>

      <div className="container">
        <IngredientSelector
          selectedIngredients={selectedIngredients}
          setSelectedIngredients={setSelectedIngredients}
          fetchRecipes={fetchRecipes}
        />

        {loading && <p style={{ textAlign: "center", fontWeight: "bold" }}>Loading recipes...</p>}

        <div className="recipes-section">
          <h2>Recipes</h2>
          {recipes.map((recipe) => (
            <RecipeCard key={recipe.id} recipe={recipe} />
          ))}
        </div>
      </div>
    </div>
  );
}

export default App;
